package main

import "fmt"

func main() {
	var row, col int
	fmt.Scan(&row, &col)

	grid := make([][]int, row)

	for i := 0; i < row; i++ {
		grid[i] = make([]int, col)
		for j := 0; j < col; j++ {
			fmt.Scan(&grid[i][j])
		}
	}

	for i := 0; i < row; i++ {
		fmt.Println(grid[i])
	}
}
